import React, { useEffect, useState } from 'react';
import { toast } from 'react-toastify';
import { adminApi } from '../api/authApi';
import { useAuth } from '../context/AuthContext';
import { Shield, Users, Trash2 } from 'lucide-react';

const AdminDashboard = () => {
  const { user } = useAuth();

  // controlled visibility
  const [viewMode, setViewMode] = useState(null); // null | 'all' | 'students'
  const [users, setUsers] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedRole, setSelectedRole] = useState('all'); // all|admin|alumni|student
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const roleToLabel = (role) => {
    if (role === 'admin') return 'Admin';
    if (role === 'alumni') return 'Alumni';
    if (role === 'student') return 'Student';
    return role || '-';
  };

  const roleBadgeClass = (role) => {
    if (role === 'admin') return 'bg-red-100 text-red-700';
    if (role === 'alumni') return 'bg-blue-100 text-blue-700';
    if (role === 'student') return 'bg-green-100 text-green-700';
    return 'bg-gray-100 text-gray-700';
  };

  const buildParams = () => {
    const params = {};

    const trimmedSearch = searchTerm.trim();
    if (trimmedSearch) params.search = trimmedSearch;

    if (viewMode === 'students') {
      params.role = 'student';
    } else if (viewMode === 'all' && selectedRole !== 'all') {
      params.role = selectedRole;
    }

    return params;
  };

  const fetchUsers = async () => {
    if (!viewMode) return;

    setError(null);
    try {
      setLoading(true);
      const params = buildParams();
      const response = await adminApi.getUsers(params);
      setUsers(response.data?.data || []);
    } catch (err) {
      setUsers([]);
      setError(err?.response?.data?.message || 'Failed to fetch users');
    } finally {
      setLoading(false);
    }
  };

  // Debounced search/filters (respects viewMode).
  useEffect(() => {
    if (!viewMode) return;
    const handle = setTimeout(() => {
      fetchUsers();
    }, 400);
    return () => clearTimeout(handle);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [viewMode, searchTerm, selectedRole]);

  const handleViewAll = () => {
    setViewMode('all');
    setSelectedRole('all');
    setUsers([]);
    setError(null);
  };

  const handleViewStudents = () => {
    setViewMode('students');
    setSelectedRole('student');
    setUsers([]);
    setError(null);
  };

  const handleDeleteUser = async (userId) => {
    const confirmed = window.confirm('Are you sure you want to delete this user? This action cannot be undone.');
    if (!confirmed) return;

    try {
      setLoading(true);
      await adminApi.deleteUser(userId);
      toast.success('User deleted successfully');
      await fetchUsers();
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Failed to delete user');
      setError(err?.response?.data?.message || 'Failed to delete user');
      setLoading(false);
    }
  };

  const isStudentView = viewMode === 'students';

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="container mx-auto px-4">
        {/* Header */}
        <div className="mb-6">
          <h1 className="text-3xl font-bold text-gray-900 mb-2 flex items-center gap-3">
            <Shield className="h-9 w-9 text-blue-700" />
            Admin Dashboard
          </h1>
          <p className="text-gray-600">
            Manage and monitor platform users{user?.name ? `, ${user.name}` : ''}.
          </p>
        </div>

        {/* Controls */}
        <div className="bg-white shadow rounded-xl p-4 md:p-6 mb-6">
          <div className="flex flex-col gap-4">
            <div className="flex flex-col md:flex-row gap-4 items-stretch">
              {/* Search */}
              <div className="flex-1">
                <label className="text-sm font-medium text-gray-700">Search</label>
                <input
                  className="form-input mt-2 w-full rounded-lg shadow-sm"
                  type="text"
                  placeholder="Search by name or email..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  disabled={!viewMode}
                />
                <p className="mt-1 text-xs text-gray-500">
                  {viewMode ? 'Search is applied to your selected view.' : 'Select a view to load users.'}
                </p>
              </div>

              {/* Role filter */}
              <div className="w-full md:w-64">
                <label className="text-sm font-medium text-gray-700">Role filter</label>
                <select
                  className="form-select mt-2 w-full rounded-lg shadow-sm"
                  value={selectedRole}
                  onChange={(e) => setSelectedRole(e.target.value)}
                  disabled={!viewMode || isStudentView}
                >
                  <option value="all">All</option>
                  <option value="admin">Admin</option>
                  <option value="alumni">Alumni</option>
                  <option value="student">Student</option>
                </select>
                {isStudentView && (
                  <p className="mt-1 text-xs text-gray-500">Student view locks role filter to Student.</p>
                )}
              </div>
            </div>

            {/* View buttons */}
            <div className="flex flex-col sm:flex-row gap-3">
              <button
                type="button"
                onClick={handleViewAll}
                className={`px-4 py-2 rounded-lg font-medium transition
                  ${viewMode === 'all' ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-800 hover:bg-gray-200'}`}
              >
                View All Users
              </button>
              <button
                type="button"
                onClick={handleViewStudents}
                className={`px-4 py-2 rounded-lg font-medium transition
                  ${viewMode === 'students' ? 'bg-green-600 text-white' : 'bg-gray-100 text-gray-800 hover:bg-gray-200'}`}
              >
                View Students Only
              </button>
            </div>

            <div className="text-sm text-gray-600 flex items-center gap-2">
              <Users className="h-4 w-4" />
              {viewMode ? `Showing ${users.length} user(s)` : 'Select a view to display users'}
            </div>
          </div>
        </div>

        {/* Empty state before loading */}
        {!viewMode ? (
          <div className="bg-white shadow rounded-xl p-6 text-center">
            <div className="mx-auto w-fit">
              <Users className="h-10 w-10 text-gray-400" />
            </div>
            <div className="mt-3 text-gray-700 font-medium">Select a view to display users</div>
            <div className="mt-1 text-sm text-gray-500">Use the buttons above to load data.</div>
          </div>
        ) : (
          <>
            {/* Error */}
            {error && (
              <div className="mb-4">
                <div className="text-sm text-red-700 bg-red-50 border border-red-200 rounded-md px-4 py-3">
                  {error}
                </div>
              </div>
            )}

            {/* Loading state */}
            {loading ? (
              <div className="bg-white shadow rounded-xl p-4 md:p-6">
                <div className="flex items-center gap-3 mb-4">
                  <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-blue-600" />
                  <div className="text-sm text-gray-700 font-medium">Loading users...</div>
                </div>

                <div className="overflow-x-auto">
                  <div className="min-w-full">
                    {Array.from({ length: 6 }).map((_, idx) => (
                      <div
                        key={idx}
                        className={`animate-pulse flex gap-4 py-3 px-4 ${idx % 2 === 0 ? 'bg-white' : 'bg-gray-50'}`}
                      >
                        <div className="h-4 bg-gray-200 rounded w-1/4" />
                        <div className="h-4 bg-gray-200 rounded w-1/3" />
                        <div className="h-4 bg-gray-200 rounded w-1/6" />
                        <div className="h-4 bg-gray-200 rounded w-1/4" />
                        <div className="h-4 bg-gray-200 rounded w-1/6 ml-auto" />
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            ) : (
              <div className="bg-white shadow rounded-xl p-0 md:p-1">
                {/* Users table */}
                <div className="overflow-x-auto rounded-xl">
                  <table className="min-w-full text-left">
                    <thead className="bg-gray-50">
                      <tr className="border-b">
                        <th className="py-3 px-4 text-sm font-semibold text-gray-700">Name</th>
                        <th className="py-3 px-4 text-sm font-semibold text-gray-700">Email</th>
                        <th className="py-3 px-4 text-sm font-semibold text-gray-700">Role</th>
                        <th className="py-3 px-4 text-sm font-semibold text-gray-700">Created At</th>
                        <th className="py-3 px-4 text-sm font-semibold text-gray-700 text-right">Actions</th>
                      </tr>
                    </thead>
                    <tbody>
                      {users.map((u, idx) => {
                        const created = u.createdAt ? new Date(u.createdAt) : null;
                        const isSelf = user?._id && u._id && user._id.toString() === u._id.toString();
                        return (
                          <tr
                            key={u._id}
                            className={`border-b transition
                              ${idx % 2 === 0 ? 'bg-white' : 'bg-gray-50'} hover:bg-gray-100`}
                          >
                            <td className="py-3 px-4 text-sm text-gray-900 font-medium">{u.name}</td>
                            <td className="py-3 px-4 text-sm text-gray-600">{u.email}</td>
                            <td className="py-3 px-4 text-sm text-gray-600">
                              <span
                                className={`inline-flex items-center rounded-full px-2 py-1 text-xs font-semibold ${roleBadgeClass(
                                  u.role
                                )}`}
                              >
                                {roleToLabel(u.role)}
                              </span>
                            </td>
                            <td className="py-3 px-4 text-sm text-gray-600">
                              {created ? created.toLocaleDateString() : '-'}
                            </td>
                            <td className="py-3 px-4 text-sm text-right">
                              {isSelf ? (
                                <span className="text-xs text-gray-500 font-medium">Current user</span>
                              ) : (
                                <button
                                  className="inline-flex items-center justify-center px-3 py-1.5 rounded-lg bg-red-600 text-white text-xs font-semibold hover:bg-red-700 transition"
                                  onClick={() => handleDeleteUser(u._id)}
                                  disabled={loading}
                                >
                                  <Trash2 className="h-4 w-4 mr-2" />
                                  Delete
                                </button>
                              )}
                            </td>
                          </tr>
                        );
                      })}

                      {users.length === 0 && (
                        <tr>
                          <td colSpan={5} className="py-12 text-center text-gray-500">
                            <div className="mx-auto w-fit">
                              <Users className="h-10 w-10 text-gray-300" />
                            </div>
                            <div className="mt-3 font-medium text-gray-700">No users found</div>
                            <div className="mt-1 text-sm text-gray-500">
                              Try adjusting your search or role filter.
                            </div>
                          </td>
                        </tr>
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;
